1вҶ’import React, { useState, useEffect, useRef } from 'react';
2вҶ’import { Wrench, Clock, CheckCircle, AlertTriangle, ArrowRight } from 'lucide-react';
3вҶ’import { emitRefresh } from '../utils/events';
4вҶ’
5вҶ’const SIGNAL_TYPES = [
6вҶ’  { value: 'MECHANIC', label: 'Mexanik', color: '#f59e0b', icon: 'рҹ”§' },
7вҶ’  { value: 'ELECTRIC', label: 'Elektrik', color: '#3b82f6', icon: 'вҡЎ' },
8вҶ’  { value: 'ASNOVA', label: 'Asnova', color: '#a855f7', icon: 'рҹ§ө' },
9вҶ’];
10вҶ’
11вҶ’const REASONS = {
12вҶ’  MECHANIC: [
13вҶ’    'Kamar uzildi', 'Galtak buzildi', 'Encoder buzildi', 'Podshipnik yemirildi',
14вҶ’    "Yog' yetishmayapti", "Tishli g'ildirak buzildi", 'Servomotor hatoligi', 'Boshqa'
15вҶ’  ],
16вҶ’  ELECTRIC: [
17вҶ’    'Motor ishlamayabdi', 'Tugmalar ishlamaybdi', 'Sensor ishlamayapti',
18вҶ’    'Magnit ishlamayabdi', 'Boshqa'
19вҶ’  ],
20вҶ’  ASNOVA: [
21вҶ’    'Asnova tugadi', 'Asnova yirtildi', "Asnova sifatsiz",
22вҶ’    "Asnova o'rnatilmagan", 'Boshqa'
23вҶ’  ],
24вҶ’};
25вҶ’
26вҶ’const DIRECTIONS = {
27вҶ’  MECHANIC: [
28вҶ’    { value: 'MECHANIC', label: 'Mexanik', icon: 'рҹ”§' },
29вҶ’    { value: 'ELECTRIC', label: 'Elektrik', icon: 'вҡЎ' },
30вҶ’    { value: 'UZLAVYAZ', label: 'Uzlavyaz', icon: 'рҹ§ө' },
31вҶ’  ],
32вҶ’  ELECTRIC: [
33вҶ’    { value: 'ELECTRIC', label: 'Elektrik', icon: 'вҡЎ' },
34вҶ’    { value: 'MECHANIC', label: 'Mexanik', icon: 'рҹ”§' },
35вҶ’    { value: 'UZLAVYAZ', label: 'Uzlavyaz', icon: 'рҹ§ө' },
36вҶ’  ],
37вҶ’  ASNOVA: [
38вҶ’    { value: 'UZLAVYAZ', label: 'Uzlavyaz', icon: 'рҹ§ө' },
39вҶ’    { value: 'MASTER', label: 'Master', icon: 'рҹ‘”' },
40вҶ’    { value: 'NAZORATCHI', label: 'Nazoratchi', icon: 'рҹӣЎпёҸ' },
41вҶ’  ],
42вҶ’};
43вҶ’
44вҶ’const MechanicPanel = ({ user }) => {
45вҶ’  const [calls, setCalls] = useState([]);
46вҶ’  const [filter, setFilter] = useState('ALL');
47вҶ’  const [showCallForm, setShowCallForm] = useState(false);
**48вҶ’  const [callForm, setCallForm] = useState({ machine_id: '', signal_type: 'MECHANIC' });
49вҶ’  const [selectedReasons, setSelectedReasons] = useState([]);
50вҶ’  const [customReason, setCustomReason] = useState('');
51вҶ’  const [showReasons, setShowReasons] = useState(false);
52вҶ’  const [forwardCall, setForwardCall] = useState(null);
53вҶ’  const prevCallsRef = useRef([]);
54вҶ’
55вҶ’  const token = localStorage.getItem('token');
56вҶ’  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
57вҶ’  const API = `http://${window.location.hostname}:8000`;
58вҶ’
59вҶ’  const playAlert = (signalType) => {
60вҶ’    try {
61вҶ’      const ctx = new (window.AudioContext || window.webkitAudioContext)();
62вҶ’      const osc = ctx.createOscillator();
63вҶ’      const gain = ctx.createGain();
64вҶ’      osc.connect(gain);
65вҶ’      gain.connect(ctx.destination);
66вҶ’      gain.gain.value = 0.3;
67вҶ’      if (signalType === 'ELECTRIC') { osc.frequency.value = 660; osc.type = 'sawtooth'; }
68вҶ’      else if (signalType === 'ASNOVA') { osc.frequency.value = 440; osc.type = 'triangle'; }
69вҶ’      else { osc.frequency.value = 520; osc.type = 'sine'; }
70вҶ’      osc.start();
71вҶ’      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.5);
72вҶ’      osc.stop(ctx.currentTime + 1.5);
73вҶ’    } catch (e) {}
74вҶ’  };
75вҶ’
76вҶ’  const fetchCalls = async () => {
77вҶ’    try {
78вҶ’      const res = await fetch(`${API}/mechanic-calls`, { headers });
79вҶ’      if (res.ok) {
80вҶ’        const data = await res.json();
81вҶ’        const newPending = data.filter(c => c.status === 'PENDING');
82вҶ’        const oldPending = prevCallsRef.current.filter(c => c.status === 'PENDING');
83вҶ’        if (newPending.length > oldPending.length) {
84вҶ’          const newCall = newPending.find(nc => !oldPending.some(oc => oc.id === nc.id));
85вҶ’          if (newCall) playAlert(newCall.signal_type || 'MECHANIC');
86вҶ’        }
87вҶ’        prevCallsRef.current = data;
88вҶ’        setCalls(data);
89вҶ’      }
90вҶ’    } catch (e) {}
91вҶ’  };
92вҶ’
93вҶ’  useEffect(() => {
94вҶ’    fetchCalls();
95вҶ’    const i = setInterval(fetchCalls, 3000);
96вҶ’    const h = () => fetchCalls();
97вҶ’    window.addEventListener('app-refresh', h);
98вҶ’    return () => { clearInterval(i); window.removeEventListener('app-refresh', h); };
99вҶ’  }, []);
100вҶ’
101вҶ’  const updateStatus = async (id, status) => {
102вҶ’    try {
103вҶ’      await fetch(`${API}/mechanic-calls/${id}`, {
104вҶ’        method: 'PUT', headers, body: JSON.stringify({ status })
105вҶ’      });
106вҶ’      fetchCalls();
107вҶ’      emitRefresh();
108вҶ’    } catch (e) {}
109вҶ’  };
110вҶ’
111вҶ’  const handleForward = async (callId, newSignalType) => {
112вҶ’    try {
113вҶ’      await fetch(`${API}/mechanic-calls/${callId}`, {
114вҶ’        method: 'PUT', headers, body: JSON.stringify({ status: 'PENDING', signal_type: newSignalType })
115вҶ’      });
116вҶ’      setForwardCall(null);
117вҶ’      fetchCalls();
118вҶ’      emitRefresh();
119вҶ’    } catch (e) {}
120вҶ’  };
121вҶ’
122вҶ’  const handleCreateCall = async () => {
123вҶ’    if (!callForm.machine_id) return;
124вҶ’    let reason = selectedReasons.filter(r => r !== 'Boshqa').join(', ');
125вҶ’    if (customReason) reason += (reason ? ', ' : '') + customReason;
126вҶ’    if (!reason) return;
127вҶ’    try {
128вҶ’      const res = await fetch(`${API}/mechanic-calls`, {
129вҶ’        method: 'POST', headers, body: JSON.stringify({ ...callForm, reason })
130вҶ’      });
131вҶ’      if (res.ok) {
**132вҶ’        setCallForm({ machine_id: '', signal_type: 'MECHANIC' });
133вҶ’        setSelectedReasons([]);
134вҶ’        setCustomReason('');
135вҶ’        setShowReasons(false);
136вҶ’        setShowCallForm(false);
137вҶ’        fetchCalls();
138вҶ’        emitRefresh();
139вҶ’      }
140вҶ’    } catch (e) {}
141вҶ’  };
142вҶ’
143вҶ’  const toggleReason = (reason) => {
144вҶ’    if (reason === 'Boshqa') {
145вҶ’      setSelectedReasons(prev => prev.includes('Boshqa') ? [] : ['Boshqa']);
146вҶ’      setCustomReason('');
147вҶ’    } else {
148вҶ’      setSelectedReasons(prev =>
149вҶ’        prev.includes(reason) ? prev.filter(r => r !== reason) : [...prev.filter(r => r !== 'Boshqa'), reason]
150вҶ’      );
151вҶ’    }
152вҶ’  };
153вҶ’
154вҶ’  const handleSignalChange = (type) => {
**155вҶ’    setCallForm({ ...callForm, signal_type: type });
156вҶ’    setSelectedReasons([]);
157вҶ’    setCustomReason('');
158вҶ’    setShowReasons(true);
159вҶ’  };
160вҶ’
161вҶ’  const hasOther = selectedReasons.includes('Boshqa');
162вҶ’  const currentReasons = REASONS[callForm.signal_type] || REASONS.MECHANIC;
163вҶ’  const currentDirections = DIRECTIONS[callForm.signal_type] || DIRECTIONS.MECHANIC;
164вҶ’
165вҶ’  const statusColors = {
166вҶ’    PENDING: { bg: 'rgba(251,191,36,0.15)', color: '#fbbf24', icon: <Clock size={14} /> },
167вҶ’    IN_PROGRESS: { bg: 'rgba(59,130,246,0.15)', color: '#3b82f6', icon: <Wrench size={14} /> },
168вҶ’    RESOLVED: { bg: 'rgba(34,197,94,0.15)', color: '#22c55e', icon: <CheckCircle size={14} /> },
169вҶ’  };
170вҶ’
171вҶ’  const filtered = filter === 'ALL' ? calls : calls.filter(c => c.status === filter);
172вҶ’  const pendingCount = calls.filter(c => c.status === 'PENDING').length;
173вҶ’  const allMachineIds = Array.from({ length: 68 }, (_, i) => `S${i + 1}`);
174вҶ’
175вҶ’  const canForward = (call) => {
176вҶ’    if (call.status !== 'IN_PROGRESS') return false;
177вҶ’    return ['MECHANIC', 'ELECTRIC', 'ASNOVA', 'ADMIN', 'MASTER', 'NAZORATCHI', 'UZLAVYAZ'].includes(user.role);
178вҶ’  };
179вҶ’
180вҶ’  const forwardTargets = (call) => {
181вҶ’    const targets = [];
182вҶ’    if (call.signal_type === 'MECHANIC') {
183вҶ’      targets.push({ value: 'ELECTRIC', label: 'Elektrikga', icon: 'вҡЎ' });
184вҶ’      targets.push({ value: 'ASNOVA', label: 'Uzlavyazga', icon: 'рҹ§ө' });
185вҶ’    } else if (call.signal_type === 'ELECTRIC') {
186вҶ’      targets.push({ value: 'MECHANIC', label: 'Mexanikka', icon: 'рҹ”§' });
187вҶ’      targets.push({ value: 'ASNOVA', label: 'Uzlavyazga', icon: 'рҹ§ө' });
188вҶ’    } else if (call.signal_type === 'ASNOVA') {
189вҶ’      targets.push({ value: 'MECHANIC', label: 'Mexanikka', icon: 'рҹ”§' });
190вҶ’      targets.push({ value: 'ELECTRIC', label: 'Elektrikga', icon: 'вҡЎ' });
191вҶ’    }
192вҶ’    return targets;
193вҶ’  };
194вҶ’
195вҶ’  const getDirectionLabel = (dir) => {
196вҶ’    const allDirs = [...DIRECTIONS.MECHANIC, ...DIRECTIONS.ASNOVA];
197вҶ’    const found = allDirs.find(d => d.value === dir);
198вҶ’    return found ? found.label : dir;
199вҶ’  };
200вҶ’
201вҶ’  return (
202вҶ’    <div style={{ padding: '1.5rem' }}>
203вҶ’      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '8px' }}>
204вҶ’        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '10px' }}>
205вҶ’          <Wrench size={24} />
206вҶ’          Chaqiruvlar
207вҶ’          {pendingCount > 0 && (
208вҶ’            <span style={{
209вҶ’              background: '#ef4444', color: 'white', borderRadius: '50%',
210вҶ’              width: '28px', height: '28px', display: 'flex', alignItems: 'center', justifyContent: 'center',
211вҶ’              fontSize: '0.75rem', fontWeight: 800, animation: 'pulse 1.5s infinite'
212вҶ’            }}>{pendingCount}</span>
213вҶ’          )}
214вҶ’        </h2>
215вҶ’        {(user.role === 'MASTER' || user.role === 'ADMIN' || user.role === 'NAZORATCHI' || user.role === 'UZLAVYAZ') && (
216вҶ’          <button onClick={() => { setShowCallForm(!showCallForm); setShowReasons(false); setSelectedReasons([]); setCustomReason(''); }} style={{
217вҶ’            display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
218вҶ’            background: '#ef4444', color: 'white', border: 'none', borderRadius: '10px',
219вҶ’            cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
220вҶ’          }}>
221вҶ’            <AlertTriangle size={16} /> Chaqiruv Yuborish
222вҶ’          </button>
223вҶ’        )}
224вҶ’      </div>
225вҶ’
226вҶ’      {showCallForm && (
227вҶ’        <div style={{
228вҶ’          background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px',
229вҶ’          padding: '1.5rem', marginBottom: '1.5rem'
230вҶ’        }}>
231вҶ’          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Yangi Chaqiruv</h3>
232вҶ’
233вҶ’          <div style={{ marginBottom: '1rem' }}>
234вҶ’            <label style={labelStyle}>Stanok</label>
235вҶ’            <select className="input-field" style={{ marginTop: '4px' }}
236вҶ’              value={callForm.machine_id}
237вҶ’              onChange={e => setCallForm({ ...callForm, machine_id: e.target.value })}>
238вҶ’              <option value="">Tanlang...</option>
239вҶ’              {allMachineIds.map(id => <option key={id} value={id}>{id}</option>)}
240вҶ’            </select>
241вҶ’          </div>
242вҶ’
243вҶ’          <label style={labelStyle}>Signal Turi</label>
244вҶ’          <div style={{ display: 'flex', gap: '8px', marginTop: '8px', marginBottom: '1rem' }}>
245вҶ’            {SIGNAL_TYPES.map(st => (
246вҶ’              <button key={st.value} onClick={() => handleSignalChange(st.value)} style={{
247вҶ’                flex: 1, padding: '12px', borderRadius: '10px', border: '2px solid',
248вҶ’                borderColor: callForm.signal_type === st.value ? st.color : 'rgba(255,255,255,0.1)',
249вҶ’                background: callForm.signal_type === st.value ? `${st.color}22` : 'rgba(255,255,255,0.03)',
250вҶ’                color: callForm.signal_type === st.value ? st.color : 'var(--text-muted)',
251вҶ’                cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem', textAlign: 'center'
252вҶ’              }}>
253вҶ’                <div style={{ fontSize: '1.5rem', marginBottom: '4px' }}>{st.icon}</div>
254вҶ’                {st.label}
255вҶ’              </button>
256вҶ’            ))}
257вҶ’          </div>
258вҶ’
259вҶ’          <div style={{
260вҶ’            maxHeight: showReasons ? '800px' : '0',
261вҶ’            overflow: 'hidden',
262вҶ’            transition: 'max-height 0.4s ease, opacity 0.3s ease',
263вҶ’            opacity: showReasons ? 1 : 0,
264вҶ’          }}>
**265вҶ’            {/* Yo'naltirish removed from call form - now shown only when IN_PROGRESS */}
266вҶ’            <div style={{
267вҶ’              display: 'flex', flexWrap: 'wrap', gap: '8px', marginTop: '8px',
268вҶ’              padding: '12px', background: 'rgba(0,0,0,0.2)', borderRadius: '12px'
269вҶ’            }}>
270вҶ’              {currentReasons.map(reason => {
271вҶ’                const isSelected = selectedReasons.includes(reason);
272вҶ’                const isOther = reason === 'Boshqa';
273вҶ’                return (
274вҶ’                  <button key={reason} onClick={() => toggleReason(reason)} style={{
275вҶ’                    padding: '8px 16px', borderRadius: '20px',
276вҶ’                    border: `2px solid ${isSelected ? (isOther ? '#a855f7' : '#22c55e') : 'rgba(255,255,255,0.1)'}`,
277вҶ’                    background: isSelected ? (isOther ? 'rgba(168,85,247,0.2)' : 'rgba(34,197,94,0.15)') : 'rgba(255,255,255,0.03)',
278вҶ’                    color: isSelected ? (isOther ? '#a855f7' : '#22c55e') : 'var(--text-muted)',
279вҶ’                    cursor: 'pointer', fontWeight: 600, fontSize: '0.8rem',
280вҶ’                    transition: 'all 0.2s ease',
281вҶ’                  }}>
282вҶ’                    {isSelected ? 'вң“ ' : ''}{reason}
283вҶ’                  </button>
284вҶ’                );
285вҶ’              })}
286вҶ’            </div>
287вҶ’
288вҶ’            {hasOther && (
289вҶ’              <div style={{ marginTop: '0.75rem' }}>
290вҶ’                <input className="input-field" style={{ marginTop: '4px' }}
291вҶ’                  value={customReason}
292вҶ’                  onChange={e => setCustomReason(e.target.value)}
293вҶ’                  placeholder="Sababni yozing..." autoFocus />
294вҶ’              </div>
295вҶ’            )}
296вҶ’          </div>
297вҶ’
298вҶ’          <div style={{ display: 'flex', gap: '8px', marginTop: '1rem' }}>
299вҶ’            <button onClick={handleCreateCall} disabled={!callForm.machine_id || (selectedReasons.length === 0 && !customReason)} style={{
300вҶ’              padding: '10px 20px',
301вҶ’              background: (!callForm.machine_id || (selectedReasons.length === 0 && !customReason)) ? 'rgba(239,68,68,0.3)' : '#ef4444',
302вҶ’              color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 700
303вҶ’            }}>Yuborish</button>
304вҶ’            <button onClick={() => { setShowCallForm(false); setShowReasons(false); setSelectedReasons([]); setCustomReason(''); }} style={{
305вҶ’              padding: '10px 20px', background: 'rgba(255,255,255,0.05)', color: 'var(--text-muted)',
306вҶ’              border: '1px solid var(--panel-border)', borderRadius: '10px', cursor: 'pointer', fontWeight: 600
307вҶ’            }}>Bekor</button>
308вҶ’          </div>
309вҶ’        </div>
310вҶ’      )}
311вҶ’
312вҶ’      <div style={{ display: 'flex', gap: '8px', marginBottom: '1.5rem', flexWrap: 'wrap' }}>
313вҶ’        {['ALL', 'PENDING', 'IN_PROGRESS', 'RESOLVED'].map(s => (
314вҶ’          <button key={s} onClick={() => setFilter(s)} style={{
315вҶ’            padding: '8px 16px', borderRadius: '8px',
316вҶ’            border: filter === s ? '2px solid var(--primary)' : '1px solid var(--panel-border)',
317вҶ’            background: filter === s ? 'rgba(0,210,255,0.1)' : 'transparent',
318вҶ’            color: filter === s ? 'var(--primary)' : 'var(--text-muted)',
319вҶ’            cursor: 'pointer', fontWeight: 600, fontSize: '0.8rem'
320вҶ’          }}>
321вҶ’            {s === 'ALL' ? 'Hammasi' : s === 'PENDING' ? 'Kutilmoqda' : s === 'IN_PROGRESS' ? 'Jarayonda' : 'Hal qilingan'}
322вҶ’          </button>
323вҶ’        ))}
324вҶ’      </div>
325вҶ’
326вҶ’      <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
327вҶ’        {filtered.length === 0 && (
328вҶ’          <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--text-muted)' }}>
329вҶ’            <CheckCircle size={40} style={{ marginBottom: '1rem', opacity: 0.5 }} />
330вҶ’            <p>Chaqiruvlar yo'q</p>
331вҶ’          </div>
332вҶ’        )}
333вҶ’        {filtered.map(call => {
334вҶ’          const sc = statusColors[call.status] || statusColors.PENDING;
335вҶ’          const sig = SIGNAL_TYPES.find(s => s.value === call.signal_type) || SIGNAL_TYPES[0];
336вҶ’          return (
337вҶ’            <div key={call.id} style={{
338вҶ’              background: 'var(--card)', border: `1px solid ${call.status === 'PENDING' ? sig.color + '44' : 'var(--panel-border)'}`,
339вҶ’              borderRadius: '12px', padding: '1rem 1.25rem',
340вҶ’              display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: '8px',
341вҶ’              animation: call.status === 'PENDING' ? 'slideIn 0.3s ease' : 'none'
342вҶ’            }}>
343вҶ’              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1, minWidth: 0 }}>
344вҶ’                <div style={{
345вҶ’                  width: '44px', height: '44px', borderRadius: '10px', flexShrink: 0,
346вҶ’                  background: `${sig.color}22`, color: sig.color,
347вҶ’                  display: 'flex', alignItems: 'center', justifyContent: 'center',
348вҶ’                  fontSize: '1.3rem'
349вҶ’                }}>
350вҶ’                  {sig.icon}
351вҶ’                </div>
352вҶ’                <div style={{ minWidth: 0 }}>
353вҶ’                  <div style={{ fontWeight: 700, fontSize: '0.9rem', display: 'flex', alignItems: 'center', gap: '6px', flexWrap: 'wrap' }}>
354вҶ’                    Stanok {call.machine_id}
355вҶ’                    <span style={{
356вҶ’                      padding: '2px 8px', borderRadius: '4px',
357вҶ’                      fontSize: '0.6rem', fontWeight: 700, background: `${sig.color}22`, color: sig.color
358вҶ’                    }}>{sig.label}</span>
359вҶ’                    {call.direction && (
360вҶ’                      <span style={{
361вҶ’                        padding: '2px 8px', borderRadius: '4px',
362вҶ’                        fontSize: '0.6rem', fontWeight: 700, background: 'rgba(0,210,255,0.15)', color: '#00d2ff'
363вҶ’                      }}>вҶ’ {getDirectionLabel(call.direction)}</span>
364вҶ’                    )}
365вҶ’                  </div>
366вҶ’                  <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
367вҶ’                    {call.reason || "Sabab ko'rsatilmagan"} вҖ” {new Date(call.created_at).toLocaleString()}
368вҶ’                  </div>
369вҶ’                </div>
370вҶ’              </div>
371вҶ’              <div style={{ display: 'flex', gap: '6px', alignItems: 'center', flexWrap: 'wrap' }}>
372вҶ’                <span style={{
373вҶ’                  padding: '4px 10px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: 700,
374вҶ’                  background: sc.bg, color: sc.color
375вҶ’                }}>
376вҶ’                  {call.status === 'PENDING' ? 'Kutilmoqda' : call.status === 'IN_PROGRESS' ? 'Jarayonda' : 'Hal qilingan'}
